#include <stdlib.h>
int cmp(const void *a, const void *b){return (*(int*)a)-(*(int*)b);} 
int main(){int T; if(scanf("%d", &T)!=1) return 0; while(T--){int N,X; scanf("%d %d", &N, &X); int *arr = (int*)malloc(N*sizeof(int)); for(int i=0;i<N;i++) scanf("%d", &arr[i]); qsort(arr, N, sizeof(int), cmp); int ans = arr[N-X] - 1; printf("%d\n", ans); free(arr);} return 0;}

